def _extract_section(text: str, heading: str) -> list[str]:
    """Return lines under `heading` (until the next ## heading)."""
    in_section = False
    out: list[str] = []
    for line in text.splitlines():
        if line.startswith(heading):
            in_section = True
            continue
        if in_section and line.startswith("## "):
            break
        if in_section:
            out.append(line)
    return out


